    $("#gd-contact-methods-table").appTable({source: '<?php echo_uri("grupo_donato/contacts/list_data"); ?>', serverSide: true, filterParams: {person_id: "<?php echo (int) $person->id; ?>"}, columns: [
        {title: '<?php echo app_lang("gd_contact_type"); ?>'}, {title: '<?php echo app_lang("gd_label"); ?>'}, {title: '<?php echo app_lang("gd_contact_value"); ?>'}, {title: '<?php echo app_lang("gd_primary"); ?>'}, {title: '<?php echo app_lang("gd_status"); ?>'}, {title: '<i data-feather="menu" class="icon-16"></i>', "class": "text-center option w80"}
    ]});
    $("#gd-person-accounts-table").appTable({source: '<?php echo_uri("grupo_donato/account-people/list_data"); ?>', serverSide: true, filterParams: {person_id: "<?php echo (int) $person->id; ?>"}, columns: [
        {title: '<?php echo app_lang("gd_customer_account"); ?>'}, {title: '<?php echo app_lang("gd_role"); ?>'}, {title: '<?php echo app_lang("gd_primary"); ?>'}, {title: '<?php echo app_lang("gd_financial_responsible"); ?>'}, {title: '<?php echo app_lang("gd_status"); ?>'}, {title: '<i data-feather="menu" class="icon-16"></i>', "class": "text-center option w80"}
    ]});
});
